1	package gitproto
2	
3	import (
4		"bytes"
5		"context"
6		"fmt"
7		"io"
8		"os"
9	
10		"github.com/go-git/go-git/v6/plumbing"
11		"github.com/go-git/go-git/v6/plumbing/format/packfile"
12		"github.com/go-git/go-git/v6/plumbing/protocol/packp"
13		"github.com/go-git/go-git/v6/plumbing/protocol/packp/capability"
14		"github.com/go-git/go-git/v6/plumbing/protocol/packp/sideband"
15		"github.com/go-git/go-git/v6/plumbing/storer"
16		"github.com/go-git/go-git/v6/plumbing/transport"
17	)
18	
19	// PushCommand represents a single ref update command.
20	type PushCommand struct {
21		Name   plumbing.ReferenceName
22		Old    plumbing.Hash
23		New    plumbing.Hash
24		Delete bool
25	}
26	
27	// Pusher wraps target-side receive-pack state behind a smaller execution API.
28	type Pusher struct {
29		Conn    *Conn
30		Adv     *packp.AdvRefs
31		Verbose bool
32	}
33	
34	// NewPusher builds a target-side push executor.
35	func NewPusher(conn *Conn, adv *packp.AdvRefs, verbose bool) Pusher {
36		return Pusher{Conn: conn, Adv: adv, Verbose: verbose}
37	}
38	
39	// PushPack streams a pack to the target.
40	func (p Pusher) PushPack(ctx context.Context, commands []PushCommand, pack io.ReadCloser) error {
41		return PushPack(ctx, p.Conn, p.Adv, commands, pack, p.Verbose)
42	}
43	
44	// PushCommands sends ref-only updates without a pack.
45	func (p Pusher) PushCommands(ctx context.Context, commands []PushCommand) error {
46		return PushCommands(ctx, p.Conn, p.Adv, commands, p.Verbose)
47	}
48	
49	// PushObjects encodes and pushes locally materialized objects.
50	func (p Pusher) PushObjects(ctx context.Context, commands []PushCommand, store storer.Storer, hashes []plumbing.Hash) error {
51		return PushObjects(ctx, p.Conn, p.Adv, commands, store, hashes, p.Verbose)
52	}
53	
54	// buildUpdateRequest builds the receive-pack update request.
55	func buildUpdateRequest(
56		adv *packp.AdvRefs,
57		commands []PushCommand,
58		verbose bool,
59	) (*packp.UpdateRequests, bool, bool, error) {
60		req := packp.NewUpdateRequests()
61		if sb := PreferredSideband(adv.Capabilities); sb != "" {
62			_ = req.Capabilities.Set(sb)
63		}
64		if adv.Capabilities.Supports(capability.ReportStatus) {
65			_ = req.Capabilities.Set(capability.ReportStatus)
66		}
67	
68		hasDelete := false
69		hasUpdates := false
70		for _, cmd := range commands {
71			c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
72			if cmd.Delete {
73				c.New = plumbing.ZeroHash
74				hasDelete = true
75			} else {
76				c.New = cmd.New
