// TestDebugNAK captures the raw upload-pack response bytes in the
// divergent-branch replicate scenario to diagnose "unknown channel NAK".
func TestDebugNAK(t *testing.T) {
	sourceRepo, sourceFS := newSourceRepo(t)
	targetRepo, _ := newSourceRepo(t)
	makeCommits(t, sourceRepo, sourceFS, 3)

	sourceServer := newSmartHTTPRepoServer(t, sourceRepo)
	targetServer := newSmartHTTPRepoServer(t, targetRepo)
	targetServer.receivePackThinCap = true
	defer sourceServer.Close()
	defer targetServer.Close()

	if _, err := Run(context.Background(), Config{
		Source: Endpoint{URL: sourceServer.RepoURL()},
		Target: Endpoint{URL: targetServer.RepoURL()},
	}); err != nil {
		t.Fatalf("seed sync failed: %v", err)
	}

	head, err := sourceRepo.Reference(plumbing.NewBranchReferenceName(testBranch), true)
	if err != nil {
		t.Fatal(err)
	}
	headCommit, err := sourceRepo.CommitObject(head.Hash())
	if err != nil {
		t.Fatal(err)
	}
	olderHash := headCommit.ParentHashes[0]
	branchRef := plumbing.NewBranchReferenceName(testBranch)
	if err := sourceRepo.Storer.SetReference(plumbing.NewHashReference(branchRef, olderHash)); err != nil {
		t.Fatal(err)
	}

	// Capture raw upload-pack response bytes.
	sourceServer.uploadPackRaw = func(w http.ResponseWriter, r *http.Request, body []byte) bool {
		t.Logf("upload-pack request body bytes: %d", len(body))
		t.Logf("request body (textish):\n%s", printablePkts(body))

		var buf bytes.Buffer
		reader := io.NopCloser(bytes.NewReader(body))
		writer := nopWriteCloser{&buf}
		if err := transport.UploadPack(r.Context(), sourceRepo.Storer, reader, writer, &transport.UploadPackOptions{
			StatelessRPC: true,
		}); err != nil {
			t.Logf("upload-pack error: %v", err)
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return true
		}
		t.Logf("upload-pack response bytes: %d", buf.Len())
		t.Logf("response dump:\n%s", hexdumpPkts(buf.Bytes()))

		w.Header().Set("Content-Type", fmt.Sprintf("application/x-%s-result", serviceUploadPack))
		w.Write(buf.Bytes())
		return true
	}

	_, err = Run(context.Background(), Config{
		Source: Endpoint{URL: sourceServer.RepoURL()},
		Target: Endpoint{URL: targetServer.RepoURL()},
		Mode:   modeReplicate,
	})
	if err != nil {
		t.Logf("replicate error: %v", err)
	}
}

func printablePkts(data []byte) string {
	var buf bytes.Buffer
	r := bytes.NewReader(data)
	for {
		l, p, err := pktline.ReadLine(r)
		if err != nil {
			fmt.Fprintf(&buf, "[read err: %v]\n", err)
			break
		}
		fmt.Fprintf(&buf, "pkt %04x: %q\n", l, p)
		if l == 0 {
			continue
		}
	}
	return buf.String()
}

func hexdumpPkts(data []byte) string {
	var buf bytes.Buffer
	r := bytes.NewReader(data)
	for {
		l, p, err := pktline.ReadLine(r)
		if err != nil {
			fmt.Fprintf(&buf, "[read err: %v, remaining=%d]\n", err, r.Len())
			if r.Len() > 0 {
				rest, _ := io.ReadAll(r)
				fmt.Fprintf(&buf, "remaining raw (first 32): %x\n", rest[:min(32, len(rest))])
			}
			break
		}
		preview := p
		if len(preview) > 40 {
			preview = preview[:40]
		}
		fmt.Fprintf(&buf, "pkt len=%04x channel=%02x content=%q\n", l, firstByte(p), preview)
	}
	return buf.String()
}

func firstByte(b []byte) byte {
	if len(b) == 0 {
		return 0
	}
	return b[0]
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}
