		Target: Endpoint{URL: targetServer.RepoURL()},
		Force:  true,
	}); err != nil {
		t.Fatalf("expected forced sync to succeed: %v", err)
	}

	assertHeadsMatch(t, sourceRepo, targetRepo, testBranch)
}

