	if err := fs.Parse(args); err != nil {
		return err
	}
	req.Protocol = gitsync.ProtocolMode(probeProtocol)

	positional := fs.Args()
	if req.Source.URL == "" && len(positional) > 0 {
		req.Source.URL = positional[0]
	}
	if *targetURL == "" && len(positional) > 1 {
		*targetURL = positional[1]
	}
