	}

	tests := []struct {
		name            string
		branches        []string
		includeTags     bool
		wantBranchCount int
		wantTagCount    int
	}{
		{
			name:            "no filter returns all branches",
			wantBranchCount: 2,
			wantTagCount:    0,
		},
		{
			name:            "filter to single branch",
			branches:        []string{"main"},
			wantBranchCount: 1,
			wantTagCount:    0,
		},
		{
			name:            "include tags adds tag refs",
			includeTags:     true,
			wantBranchCount: 2,
			wantTagCount:    1,
		},
		{
			name:            "branch filter plus tags",
			branches:        []string{"main"},
			includeTags:     true,
			wantBranchCount: 1,
			wantTagCount:    1,
		},
	}

