97	func loadEntireDBActiveUser(host, configDir string) (string, bool) {
98		data, err := os.ReadFile(filepath.Join(configDir, "hosts.json"))
99		if err != nil {
100			return "", false
101		}
102		var hosts map[string]*entireAuthHostInfo
103		if err := json.Unmarshal(data, &hosts); err != nil {
104			return "", false
105		}
106		info := hosts[host]
107		if info == nil || info.ActiveUser == "" {
108			return "", false
