113	// getTokenWithRefresh retrieves a token, refreshing it if expired.
114	// On refresh failure, returns the stale token with a nil error rather than
115	// propagating the refresh error silently (issue #7).
116	func getTokenWithRefresh(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
117		encoded, err := ReadStoredToken(credentialService(host), username)
118		if err != nil {
119			// "Not found" means no credential is configured — not an error.
120			// Only propagate actual storage failures.
121			if isNotFound(err) {
122				return "", nil
123			}
124			return "", err
125		}
126		token, expiresAt := decodeTokenWithExpiration(encoded)
127		if token == "" {
128			return "", nil
129		}
130		if !tokenExpiredOrExpiring(expiresAt) {
131			return token, nil
132		}
133		refreshed, err := refreshAccessToken(ctx, host, username, baseURL, skipTLS)
134		if err != nil {
135			// Issue #7: surface refresh failure explicitly instead of silently reusing stale token.
136			return "", fmt.Errorf("token expired and refresh failed for %s@%s: %w", username, host, err)
137		}
138		return refreshed, nil
139	}
140	
141	func decodeTokenWithExpiration(encoded string) (string, time.Time) {
142		idx := strings.LastIndex(encoded, "|")
143		if idx == -1 {
144			return encoded, time.Time{}
145		}
146		token := encoded[:idx]
147		ts, err := strconv.ParseInt(encoded[idx+1:], 10, 64)
148		if err != nil {
149			return encoded, time.Time{}
150		}
151		return token, time.Unix(ts, 0)
152	}
153	
154	func tokenExpiredOrExpiring(expiresAt time.Time) bool {
155		if expiresAt.IsZero() {
156			return true
157		}
158		return time.Now().Add(5 * time.Minute).After(expiresAt)
159	}
160	
161	func refreshAccessToken(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
162		refreshToken, err := ReadStoredToken(credentialService(host)+":refresh", username)
163		if err != nil {
164			return "", err
165		}
166		if refreshToken == "" || baseURL == "" {
167			return "", errors.New("missing refresh token or base url")
168		}
169	
170		form := url.Values{}
171		form.Set("grant_type", "refresh_token")
172		form.Set("refresh_token", refreshToken)
173		form.Set("client_id", entireCLIClientID)
174	
175		req, err := http.NewRequestWithContext(ctx, http.MethodPost, strings.TrimRight(baseURL, "/")+"/oauth/token", strings.NewReader(form.Encode()))
176		if err != nil {
177			return "", err
178		}
179		req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
180	
181		client := &http.Client{
182			Timeout: 30 * time.Second,
183			Transport: &http.Transport{
184				TLSClientConfig: &tls.Config{InsecureSkipVerify: skipTLS}, //nolint:gosec
185			},
186		}
187		resp, err := client.Do(req)
188		if err != nil {
189			return "", err
190		}
191		defer resp.Body.Close()
192		if resp.StatusCode != http.StatusOK {
193			return "", fmt.Errorf("refresh failed with status %d", resp.StatusCode)
194		}
195	
196		var tokenResp oauthTokenResponse
197		if err := json.NewDecoder(resp.Body).Decode(&tokenResp); err != nil {
198			return "", err
199		}
200		if tokenResp.AccessToken == "" {
201			return "", errors.New("empty access token in refresh response")
202		}
203	
204		if err := WriteStoredToken(
205			credentialService(host),
206			username,
207			encodeTokenWithExpiration(tokenResp.AccessToken, tokenResp.ExpiresIn),
208		); err != nil {
209			return "", err
210		}
211		if tokenResp.RefreshToken != "" {
212			_ = WriteStoredToken(credentialService(host)+":refresh", username, tokenResp.RefreshToken)
213		}
214		return tokenResp.AccessToken, nil
215	}
216	
217	func encodeTokenWithExpiration(token string, expiresIn int64) string {
218		return fmt.Sprintf("%s|%d", token, time.Now().Unix()+expiresIn)
219	}
220	
221	func credentialService(host string) string {
222		return "entire:" + host
223	}
