package unstable

import (
	"context"
	"net/http"

	"github.com/go-git/go-git/v6/plumbing"

	"github.com/soph/git-sync/internal/syncer"
	"github.com/soph/git-sync/internal/validation"
	"github.com/soph/git-sync/pkg/gitsync"
	"github.com/soph/git-sync/pkg/gitsync/internalbridge"
)

const DefaultMaterializedMaxObjects = syncer.DefaultMaterializedMaxObjects

type (
	Result      = syncer.Result
	ProbeResult = syncer.ProbeResult
	FetchResult = syncer.FetchResult
	RefInfo     = syncer.RefInfo
	Stats       = syncer.Stats
	Measurement = syncer.Measurement
)

type Options struct {
	HTTPClient *http.Client
	Auth       gitsync.AuthProvider
}

type Client struct {
	httpClient *http.Client
	auth       gitsync.AuthProvider
}

type AdvancedOptions struct {
	CollectStats           bool
	MeasureMemory          bool
	Verbose                bool
	MaxPackBytes           int64
	BatchMaxPackBytes      int64
	MaterializedMaxObjects int
}

type ProbeRequest struct {
	Source      gitsync.Endpoint
	Target      *gitsync.Endpoint
	IncludeTags bool
	Protocol    gitsync.ProtocolMode
	Options     AdvancedOptions
}

type SyncRequest struct {
	Source  gitsync.Endpoint
	Target  gitsync.Endpoint
	Scope   gitsync.RefScope
	Policy  gitsync.SyncPolicy
	DryRun  bool
	Options AdvancedOptions
}

type BootstrapRequest struct {
	Source      gitsync.Endpoint
	Target      gitsync.Endpoint
	Scope       gitsync.RefScope
	IncludeTags bool
	Protocol    gitsync.ProtocolMode
	Options     AdvancedOptions
}

type FetchRequest struct {
	Source      gitsync.Endpoint
	Scope       gitsync.RefScope
	IncludeTags bool
	Protocol    gitsync.ProtocolMode
	HaveRefs    []string
	HaveHashes  []plumbing.Hash
	Options     AdvancedOptions
}

func New(opts Options) *Client {
	return &Client{httpClient: opts.HTTPClient, auth: opts.Auth}
}

func (c *Client) Probe(ctx context.Context, req ProbeRequest) (ProbeResult, error) {
	cfg, err := c.buildProbeConfig(ctx, req)
	if err != nil {
		return ProbeResult{}, err
	}
	return syncer.Probe(ctx, cfg)
}

func (c *Client) Plan(ctx context.Context, req SyncRequest) (Result, error) {
	planReq := req
	planReq.DryRun = true
	cfg, err := c.buildSyncConfig(ctx, planReq)
	if err != nil {
		return Result{}, err
	}
	return syncer.Run(ctx, cfg)
}

func (c *Client) Sync(ctx context.Context, req SyncRequest) (Result, error) {
	cfg, err := c.buildSyncConfig(ctx, req)
	if err != nil {
		return Result{}, err
	}
	return syncer.Run(ctx, cfg)
}

func (c *Client) Replicate(ctx context.Context, req SyncRequest) (Result, error) {
	req.Policy.Mode = gitsync.ModeReplicate
	cfg, err := c.buildSyncConfig(ctx, req)
	if err != nil {
		return Result{}, err
	}
	return syncer.Run(ctx, cfg)
}

func (c *Client) Bootstrap(ctx context.Context, req BootstrapRequest) (Result, error) {
	cfg, err := c.buildBootstrapConfig(ctx, req)
	if err != nil {
		return Result{}, err
	}
	return syncer.Bootstrap(ctx, cfg)
}

func (c *Client) Fetch(ctx context.Context, req FetchRequest) (FetchResult, error) {
	cfg, err := c.buildFetchConfig(ctx, req)
	if err != nil {
		return FetchResult{}, err
	}
	return syncer.Fetch(ctx, cfg, append([]string(nil), req.HaveRefs...), append([]plumbing.Hash(nil), req.HaveHashes...))
}

func (c *Client) buildProbeConfig(ctx context.Context, req ProbeRequest) (syncer.Config, error) {
	source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	cfg := syncer.Config{
		Source:        source,
		HTTPClient:    c.httpClient,
		IncludeTags:   req.IncludeTags,
		ShowStats:     req.Options.CollectStats,
		MeasureMemory: req.Options.MeasureMemory,
		ProtocolMode:  protocolString(req.Protocol),
		Verbose:       req.Options.Verbose,
	}
	if req.Target != nil {
		target, err := c.resolveEndpoint(ctx, *req.Target, gitsync.TargetRole)
		if err != nil {
			return syncer.Config{}, err
		}
		cfg.Target = target
	}
	return cfg, nil
}

func (c *Client) buildSyncConfig(ctx context.Context, req SyncRequest) (syncer.Config, error) {
	source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	target, err := c.resolveEndpoint(ctx, req.Target, gitsync.TargetRole)
	if err != nil {
		return syncer.Config{}, err
	}
	maxObjects := req.Options.MaterializedMaxObjects
	if maxObjects == 0 {
		maxObjects = DefaultMaterializedMaxObjects
	}
	return syncer.Config{
		Source:                 source,
		Target:                 target,
		HTTPClient:             c.httpClient,
		Branches:               append([]string(nil), req.Scope.Branches...),
		Mappings:               validationMappings(req.Scope.Mappings),
		IncludeTags:            req.Policy.IncludeTags,
		DryRun:                 req.DryRun,
		ShowStats:              req.Options.CollectStats,
		MeasureMemory:          req.Options.MeasureMemory,
		Mode:                   operationModeString(req.Policy.Mode),
		Force:                  req.Policy.Force,
		Prune:                  req.Policy.Prune,
		MaterializedMaxObjects: maxObjects,
		ProtocolMode:           protocolString(req.Policy.Protocol),
		Verbose:                req.Options.Verbose,
	}, nil
}

func (c *Client) buildBootstrapConfig(ctx context.Context, req BootstrapRequest) (syncer.Config, error) {
	source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	target, err := c.resolveEndpoint(ctx, req.Target, gitsync.TargetRole)
	if err != nil {
		return syncer.Config{}, err
	}
	return syncer.Config{
		Source:            source,
		Target:            target,
		HTTPClient:        c.httpClient,
		Branches:          append([]string(nil), req.Scope.Branches...),
		Mappings:          validationMappings(req.Scope.Mappings),
		IncludeTags:       req.IncludeTags,
		ShowStats:         req.Options.CollectStats,
		MeasureMemory:     req.Options.MeasureMemory,
		MaxPackBytes:      req.Options.MaxPackBytes,
		BatchMaxPackBytes: req.Options.BatchMaxPackBytes,
		ProtocolMode:      protocolString(req.Protocol),
		Verbose:           req.Options.Verbose,
	}, nil
}

func (c *Client) buildFetchConfig(ctx context.Context, req FetchRequest) (syncer.Config, error) {
	source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	return syncer.Config{
		Source:        source,
		HTTPClient:    c.httpClient,
		Branches:      append([]string(nil), req.Scope.Branches...),
		IncludeTags:   req.IncludeTags,
		ShowStats:     req.Options.CollectStats,
		MeasureMemory: req.Options.MeasureMemory,
		ProtocolMode:  protocolString(req.Protocol),
		Verbose:       req.Options.Verbose,
	}, nil
}

func (c *Client) authFor(ctx context.Context, endpoint gitsync.Endpoint, role gitsync.EndpointRole) (gitsync.EndpointAuth, error) {
	if c.auth == nil {
		return gitsync.EndpointAuth{}, nil
	}
	return c.auth.AuthFor(ctx, endpoint, role)
}

func (c *Client) resolveEndpoint(ctx context.Context, endpoint gitsync.Endpoint, role gitsync.EndpointRole) (syncer.Endpoint, error) {
	auth, err := c.authFor(ctx, endpoint, role)
	if err != nil {
		return syncer.Endpoint{}, err
	}
	return syncerEndpoint(endpoint, auth), nil
}

func protocolString(mode gitsync.ProtocolMode) string {
	if mode == "" {
		return string(gitsync.ProtocolAuto)
	}
	return string(mode)
}

func operationModeString(mode gitsync.OperationMode) string {
	if mode == "" {
		return string(gitsync.ModeSync)
	}
	return string(mode)
}

func syncerEndpoint(endpoint gitsync.Endpoint, auth gitsync.EndpointAuth) syncer.Endpoint {
	return internalbridge.ToSyncerEndpoint(
		internalbridge.Endpoint{URL: endpoint.URL},
		internalbridge.EndpointAuth{
			Username:      auth.Username,
			Token:         auth.Token,
			BearerToken:   auth.BearerToken,
			SkipTLSVerify: auth.SkipTLSVerify,
		},
	)
}

func validationMappings(mappings []gitsync.RefMapping) []validation.RefMapping {
	bridgeMappings := make([]internalbridge.RefMapping, 0, len(mappings))
	for _, mapping := range mappings {
		bridgeMappings = append(bridgeMappings, internalbridge.RefMapping{
			Source: mapping.Source,
			Target: mapping.Target,
		})
	}
	return internalbridge.ToValidationMappings(bridgeMappings)
}

package main

import (
	"context"
	"encoding/json"
	"errors"
	"flag"
	"fmt"
	"os"
	"strings"

	"github.com/go-git/go-git/v6/plumbing"
	"github.com/soph/git-sync/internal/validation"
	"github.com/soph/git-sync/pkg/gitsync"
	"github.com/soph/git-sync/pkg/gitsync/unstable"
)

func main() {
	if err := run(context.Background(), os.Args[1:]); err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}
}

func run(ctx context.Context, args []string) error {
	if len(args) == 0 {
		return usageError("")
	}

	switch args[0] {
	case "sync":
		return runSyncLike(ctx, "sync", args[1:], false, gitsync.ModeSync)
	case "replicate":
		return runSyncLike(ctx, "replicate", args[1:], false, gitsync.ModeReplicate)
	case "plan":
		return runSyncLike(ctx, "plan", args[1:], true, "")
	case "bootstrap":
		return runBootstrap(ctx, args[1:])
	case "probe":
		return runProbe(ctx, args[1:])
	case "fetch":
		return runFetch(ctx, args[1:])
	case "help", "-h", "--help":
		return usageError("")
	default:
		return usageError(fmt.Sprintf("unknown command %q", args[0]))
	}
}

func runSyncLike(ctx context.Context, name string, args []string, dryRun bool, defaultMode gitsync.OperationMode) error {
	fs := flag.NewFlagSet(name, flag.ContinueOnError)
	fs.SetOutput(os.Stderr)

	var mappings multiStringFlag
	var jsonOutput bool
	var sourceAuth gitsync.EndpointAuth
	var targetAuth gitsync.EndpointAuth
	req := unstable.SyncRequest{DryRun: dryRun}

	fs.StringVar(&req.Source.URL, "source-url", "", "source repository URL")
	fs.StringVar(&req.Target.URL, "target-url", "", "target repository URL")

	fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
	fs.StringVar(&targetAuth.Token, "target-token", envOr("GITSYNC_TARGET_TOKEN", ""), "target token/password")
	fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
	fs.StringVar(&targetAuth.Username, "target-username", envOr("GITSYNC_TARGET_USERNAME", "git"), "target basic auth username")
	fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
	fs.BoolVar(&targetAuth.SkipTLSVerify, "target-insecure-skip-tls-verify", envBool("GITSYNC_TARGET_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the target")

	fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
	fs.StringVar(&targetAuth.BearerToken, "target-bearer-token", envOr("GITSYNC_TARGET_BEARER_TOKEN", ""), "target bearer token")

	branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
	fs.Var(&mappings, "map", "ref mapping in src:dst form; short names map branches, full refs map exact refs")
	modeValue := operationModeFlag(defaultOperationMode(defaultMode))
	if name == "plan" {
		fs.Var(&modeValue, "mode", "operation mode: sync or replicate")
	}
	fs.BoolVar(&req.Policy.IncludeTags, "tags", false, "mirror tags")
	fs.BoolVar(&req.Policy.Force, "force", false, "allow non-fast-forward branch updates and retarget tags")
	fs.BoolVar(&req.Policy.Prune, "prune", false, "delete managed target refs that no longer exist on source")
	fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
	fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
	fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
	fs.IntVar(&req.Options.MaterializedMaxObjects, "materialized-max-objects", unstable.DefaultMaterializedMaxObjects, "abort non-relay materialized syncs above this many objects")
	protocolValue := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
	fs.Var(&protocolValue, "protocol", "protocol mode: auto, v1, or v2")
	fs.BoolVar(&req.Options.Verbose, "v", false, "verbose logging")

	if err := fs.Parse(args); err != nil {
		return err
	}
	req.Policy.Mode = gitsync.OperationMode(modeValue)
	req.Policy.Protocol = gitsync.ProtocolMode(protocolValue)

	positional := fs.Args()
	if req.Source.URL == "" && len(positional) > 0 {
		req.Source.URL = positional[0]
	}
	if req.Target.URL == "" && len(positional) > 1 {
		req.Target.URL = positional[1]
	}
	if len(positional) > 2 {
		return usageError("too many positional arguments")
	}

	if *branches != "" {
		req.Scope.Branches = splitCSV(*branches)
	}
	for _, raw := range mappings {
		mapping, err := validation.ParseMapping(raw)
		if err != nil {
			return err
		}
		req.Scope.Mappings = append(req.Scope.Mappings, gitsync.RefMapping{
			Source: mapping.Source,
			Target: mapping.Target,
		})
	}

	if req.Source.URL == "" || req.Target.URL == "" {
		return usageError(name + " requires source and target repository URLs")
	}

	client := unstable.New(unstable.Options{
		Auth: gitsync.StaticAuthProvider{Source: sourceAuth, Target: targetAuth},
	})
	var (
		result unstable.Result
		err    error
	)
	if dryRun {
		result, err = client.Plan(ctx, req)
	} else {
		if req.Policy.Mode == gitsync.ModeReplicate {
			result, err = client.Replicate(ctx, req)
		} else {
			result, err = client.Sync(ctx, req)
		}
	}
	if err != nil {
		return err
	}
	printOutput(jsonOutput, result)

	if !dryRun && result.Blocked > 0 {
		return errors.New("one or more branches were skipped because the target was not fast-forwardable")
	}
	return nil
}

func runBootstrap(ctx context.Context, args []string) error {
	fs := flag.NewFlagSet("bootstrap", flag.ContinueOnError)
