	transport.Register("http", customHTTP)
	transport.Register("https", customHTTP)

	code := m.Run()

	if originalHTTP != nil {
		transport.Register("http", originalHTTP)
	}
	if originalHTTPS != nil {
		transport.Register("https", originalHTTPS)
	}

	os.Exit(code)
}

