// progressSink returns a line-prefixing io.Writer suitable for
// sideband.Demuxer.Progress. When verbose is false it returns nil so the
// demuxer discards progress frames without allocating.
func progressSink(verbose bool, prefix string) io.Writer {
	if !verbose {
		return nil
	}
	return &prefixedLineWriter{w: os.Stderr, prefix: prefix}
}

// prefixedLineWriter writes each line of input prefixed with a fixed string.
// Git sideband progress often arrives as chunks that contain embedded '\r'
// (carriage returns used to rewrite the current line, e.g. "Resolving
// deltas:  12%\r"). We treat both '\n' and '\r' as line terminators so
// progress updates remain visible without double-printing.
type prefixedLineWriter struct {
	w       io.Writer
	prefix  string
	needPfx bool
}

func (p *prefixedLineWriter) Write(b []byte) (int, error) {
	if len(b) == 0 {
		return 0, nil
	}
	written := 0
	start := 0
	// Emit prefix lazily: only when we're about to write the first byte of
	// a new line. This avoids a trailing bare "target: " at EOF.
	if !p.needPfx {
		if _, err := io.WriteString(p.w, p.prefix); err != nil {
			return 0, err
		}
		p.needPfx = true
	}
	for i, c := range b {
		if c != '\n' && c != '\r' {
			continue
		}
		n, err := p.w.Write(b[start : i+1])
		written += n
		if err != nil {
			return written, err
		}
		start = i + 1
		if start < len(b) {
			if _, err := io.WriteString(p.w, p.prefix); err != nil {
				return written, err
			}
		} else {
			p.needPfx = false
		}
	}
	if start < len(b) {
		n, err := p.w.Write(b[start:])
		written += n
		if err != nil {
			return written, err
		}
	}
	return written, nil
}

